-- NoSQL example: MongoDB operations with Python

from pymongo import MongoClient
from datetime import datetime, timedelta
import json

# Connect to MongoDB
client = MongoClient('mongodb://localhost:27017/')
db = client['ecommerce']

# 1. Create collections with schema validation
db.create_collection('customers', validator={
    '$jsonSchema': {
        'bsonType': 'object',
        'required': ['name', 'email'],
        'properties': {
            'name': {'bsonType': 'string'},
            'email': {'bsonType': 'string', 'pattern': '^.+@.+$'},
            'tier': {
                'enum': ['basic', 'premium', 'enterprise'],
                'default': 'basic'
            },
            'address': {
                'bsonType': 'object',
                'properties': {
                    'street': {'bsonType': 'string'},
                    'city': {'bsonType': 'string'},
                    'zip': {'bsonType': 'string'}
                }
            }
        }
    }
})

# 2. Insert documents
customers = db['customers']
customer_id = customers.insert_one({
    'name': 'Alice Johnson',
    'email': 'alice@example.com',
    'tier': 'premium',
    'address': {
        'street': '123 Main St',
        'city': 'Springfield',
        'zip': '62701'
    },
    'created_at': datetime.now()
}).inserted_id

# 3. Query documents
customer = customers.find_one({'email': 'alice@example.com'})
print(f"Found: {customer['name']} ({customer['tier']})")

# 4. Update documents
customers.update_one(
    {'_id': customer_id},
    {'$set': {'tier': 'enterprise'}, '$push': {'tags': 'loyal'}}
)

# 5. Aggregation pipeline
results = db['orders'].aggregate([
    {'$match': {'status': 'completed'}},
    {'$group': {
        '_id': '$customer_id',
        'total_spent': {'$sum': '$total'},
        'order_count': {'$sum': 1},
        'avg_order': {'$avg': '$total'}
    }},
    {'$lookup': {
        'from': 'customers',
        'localField': '_id',
        'foreignField': '_id',
        'as': 'customer'
    }},
    {'$unwind': '$customer'},
    {'$project': {
        'name': '$customer.name',
        'total_spent': 1,
        'order_count': 1,
        'avg_order': {'$round': ['$avg_order', 2]}
    }},
    {'$sort': {'total_spent': -1}},
    {'$limit': 10}
])

for result in results:
    print(f"{result['name']}: ${result['total_spent']:.2f} ({result['order_count']} orders)")

# 6. Redis example
import redis

r = redis.Redis(host='localhost', port=6379, db=0)

# Cache user session
r.setex('session:user123', 3600, json.dumps({
    'user_id': '123',
    'name': 'Alice',
    'role': 'admin'
}))

# Retrieve session
session = json.loads(r.get('session:user123'))
print(f"Session: {session['name']} ({session['role']})")

# Leaderboard
r.zadd('leaderboard', {'player1': 1500, 'player2': 2000, 'player3': 1800})
top_players = r.zrevrange('leaderboard', 0, 2, withscores=True)
for player, score in top_players:
    print(f"{player.decode()}: {score}")

client.close()
